export const bnSum = (bnArr: BigNumberish[]): BigNumber => {
  return bn(bnArr.reduce((prev, curr) => bn(prev).add(bn(curr)), 0));
};

export const arrayAdd = (arrA: BigNumberish[], arrB: BigNumberish[]): BigNumber[] =>
  arrA.map((a, i) => bn(a).add(bn(arrB[i])));

